with `s + 1` indexing, which avoids the degenerate 0-th index.

lemma indepFun_rewardByCount_of_ne [StandardBorelSpace Ω] [Nonempty Ω] [Countable α]
    (h : IsAlgEnvSeq A R alg (stationaryEnv ν) P) {a b : α} (hab : a ≠ b) :
    IndepFun (fun ω s ↦ rewardByCount A R a s ω) (fun ω s ↦ rewardByCount A R b s ω) 𝔓' := by
  sorry

The reward-by-count sequences for distinct actions `a ≠ b`, restricted to positive
indices (`s + 1`), are independent.  This is the corrected version of
`indepFun_rewardByCount_of_ne`, which was false at index `s = 0`.
-/
lemma indepFun_rewardByCount_of_ne' [StandardBorelSpace Ω] [Nonempty Ω] [Countable α]
    (h : IsAlgEnvSeq A R alg (stationaryEnv ν) P) {a b : α} (hab : a ≠ b) :
    IndepFun (fun ω s ↦ rewardByCount A R a (s + 1) ω)
      (fun ω s ↦ rewardByCount A R b (s + 1) ω) 𝔓' := by
  -- The sequence of reward functions is i.i.d. by `h`.
  have h_indep : iIndepFun (fun (p : α × ℕ) ↦ rewardByCount A R p.1 (p.2 + 1))
      (P.prod (Bandit.streamMeasure ν)) :=
    iIndepFun_rewardByCount h
  rw [ iIndepFun_iff_iIndep ] at h_indep;
  -- Apply the `iIndep` hypothesis to the ranges of the functions `fun s => (a, s)` and `fun s => (b, s)`, which are disjoint because `a ≠ b`.
  have h_disjoint : Disjoint (Set.range (fun s : ℕ => (a, s))) (Set.range (fun s : ℕ => (b, s))) := by
    simp +decide [ Set.disjoint_left, hab ];
    exact hab.symm;
  -- Apply the `iIndep` hypothesis to the ranges of the functions `fun s => (a, s)` and `fun s => (b, s)`, which are disjoint because `a ≠ b`, to conclude the independence.
  have h_indep : Indep (⨆ s : ℕ, MeasurableSpace.comap (rewardByCount A R a (s + 1)) Real.measurableSpace) (⨆ s : ℕ, MeasurableSpace.comap (rewardByCount A R b (s + 1)) Real.measurableSpace) (P.prod (Bandit.streamMeasure ν)) := by
    convert indep_iSup_of_disjoint _ h_indep h_disjoint using 1;
    · refine' le_antisymm _ _ <;> simp +decide [ iSup_le_iff ];
      · intro i; exact le_iSup_of_le ( a, i ) ( le_iSup_of_le i ( by simp +decide ) ) ;
      · exact fun n => le_iSup_of_le n le_rfl;
    · simp +decide [ iSup_range ];
      refine' le_antisymm _ _ <;> simp +decide [ iSup_le_iff ];
      · intro i; exact le_iSup_of_le ( b, i ) ( le_iSup_of_le i ( le_iSup_of_le rfl le_rfl ) ) ;
      · exact fun n => le_iSup_of_le n le_rfl;
    · intro i;
      refine' le_trans _ ( MeasurableSpace.comap_le_iff_le_map.mpr _ );
      exact le_rfl;
      have h_measurable : Measurable (rewardByCount A R i.1 (i.2 + 1)) := by
        have := h.measurable_A;
        have := h.measurable_R;
        exact measurable_rewardByCount h.measurable_A h.measurable_R i.1 (i.2 + 1)
      exact measurable_iff_le_map.mp h_measurable
  convert h_indep using 1;
  ext;
  rw [ IndepFun_iff_Indep ];
